import loggingfrom .ModbusTCPMeasurements import getMeasurementDatafrom .influx_db_measurements import get_measurement_data_influxdbdef init_measurements(grid_data, config_data, server):    """    Initialize measurement data based on the communication protocol specified in the configuration.    This function retrieves measurement data from different communication protocols, such as Modbus or InfluxDB,    based on the application configuration.    :param grid_data: Dictionary containing the grid's configuration and components (e.g., transformers, topology).    :param config_data: Configuration dictionary with toolchain settings, including the communication protocol to use.    :param server: The server or communication handler required for certain protocols (e.g., Modbus, InfluxDB).    :return: MeasurementData - The measurement data retrieved from the specified communication protocol.    """    try:        # Log the start of the measurement initialization process        logging.info("Initializing measurement data based on the communication protocol.")        # Check which communication protocol is being used        protocol = config_data['Aas_config']['application']['communication_protocol']        logging.info(f"Selected communication protocol: {protocol}")        # Modbus protocol: retrieve measurement data via Modbus TCP        if protocol == 'modbus':            logging.info("Fetching measurement data via Modbus.")            vn_grid_kv = float(grid_data['gridConfig']['vnGrid_kv']) * 1000  # Convert voltage level to volts            measurement_data = getMeasurementData(                vn_grid_kv,                grid_data['topology'].copy(),                grid_data['transformers'].copy(),                server            )            logging.info("Measurement data successfully retrieved via Modbus.")        # InfluxDB protocol: retrieve measurement data from InfluxDB        elif protocol == 'influxdb':            logging.info("Fetching measurement data via InfluxDB.")            measurement_data = get_measurement_data_influxdb(server, config_data)            logging.info("Measurement data successfully retrieved via InfluxDB.")        # If the protocol is not recognized, log a warning        else:            measurement_data = None            logging.warning(f"Unsupported communication protocol: {protocol}. No measurement data retrieved.")        # Log successful measurement initialization        logging.info("Measurement initialization completed.")        return measurement_data    except Exception as e:        # Log any errors that occur during the process        logging.error(f"An error occurred during measurement initialization: {e}", exc_info=True)        return None